import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion"; // for smooth animation

function UiWidget({ apiKey, customerId, apiUrl = 'http://localhost:5000', parentUrl = '' }) {
  const [isOpen, setIsOpen] = useState(true);
  const [messages, setMessages] = useState([
    { sender: "bot", text: "Hi there! Please select a service:" },
  ]);
  const [input, setInput] = useState("");
  const [userName, setUserName] = useState(null);
  const [selectedService, setSelectedService] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [detectedUrl, setDetectedUrl] = useState('');

  const sendMessageToBackend = async (message) => {
    try {
      // Get the parent page's URL (where the widget is embedded)
      // Priority: 1) parentUrl prop (passed via query param), 2) document.referrer, 3) current URL
      let detectedParentUrl = '';

      if (parentUrl) {
        // Decode the URL that was passed as a query parameter
        detectedParentUrl = decodeURIComponent(parentUrl);
        console.log('Using parentUrl from query param:', detectedParentUrl);
      } else if (document.referrer) {
        detectedParentUrl = document.referrer;
        console.log('Using document.referrer:', document.referrer);
      } else {
        // Fallback to current URL (for testing)
        detectedParentUrl = window.location.href;
        console.log('Fallback to window.location.href:', window.location.href);
      }

      console.log('=== Widget Request Debug ===');
      console.log('Parent URL to send:', parentUrl);
      console.log('API Key:', apiKey);
      console.log('Customer ID:', customerId);

      // Store detected URL for display
      setDetectedUrl(parentUrl);

      const response = await fetch(`${apiUrl}/backend/api/widget/chat`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Widget-API-Key': apiKey,
          'X-Customer-ID': customerId,
          'X-Parent-URL': parentUrl  // Send parent page URL
        },
        body: JSON.stringify({
          message: message,
          service: selectedService || 'ChatGPT'
        })
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to get response from server');
      }

      const data = await response.json();
      return data.response || 'Sorry, I could not process your request.';
    } catch (error) {
      console.error('Error sending message:', error);
      return error.message || 'Sorry, there was an error connecting to the server. Please try again.';
    }
  };

  const handleSend = async () => {
    if (!input.trim()) return;

    setMessages((prev) => [...prev, { sender: "user", text: input }]);
    const userInput = input;
    setInput("");

    if (!userName) {
      setUserName(userInput);
      setMessages((prev) => [
        ...prev,
        { sender: "bot", text: `Nice to meet you, ${userInput}! 🌟` },
        { sender: "bot", text: `You selected: ${selectedService}` },
        { sender: "bot", text: "What can I do for you today?" },
      ]);
    } else {
      setIsLoading(true);
      const botResponse = await sendMessageToBackend(userInput);
      setIsLoading(false);
      setMessages((prev) => [
        ...prev,
        { sender: "bot", text: botResponse },
      ]);
    }
  };

  const handleServiceSelect = (service) => {
    setSelectedService(service === 'Default' || service === 'ChatGPT' ? 'ChatGPT' : service);
    setMessages((prev) => [
      ...prev,
      { sender: "user", text: service },
      { sender: "bot", text: "Great! Now, what's your name?" },
    ]);
  };

  return (
    <div>
      {/* Floating Button when closed */}
      {!isOpen && (
        <motion.button
          onClick={() => setIsOpen(true)}
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.95 }}
          style={{
            position: "fixed",
            bottom: "20px",
            right: "20px",
            borderRadius: "50%",
            width: "65px",
            height: "65px",
            background: "linear-gradient(135deg, #4e8cff 0%, #007bff 100%)",
            color: "white",
            border: "none",
            cursor: "pointer",
            fontSize: "26px",
            boxShadow: "0px 8px 20px rgba(0,0,0,0.2)",
          }}
        >
          💬
        </motion.button>
      )}

      {/* Chatbox when open */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 50 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 50 }}
            transition={{ duration: 0.3 }}
            style={{
              position: "fixed",
              bottom: "20px",
              right: "20px",
              width: "340px",
              height: "480px",
              backgroundColor: "white",
              borderRadius: "16px",
              display: "flex",
              flexDirection: "column",
              boxShadow: "0px 12px 30px rgba(0,0,0,0.25)",
              overflow: "hidden",
              fontFamily: "system-ui, sans-serif",
            }}
          >
            {/* Header */}
            <div
              style={{
                padding: "14px 16px",
                background: "linear-gradient(135deg, #4e8cff 0%, #007bff 100%)",
                color: "white",
                fontWeight: "bold",
                fontSize: "16px",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
              }}
            >
              Chat Assistant 🤖
              <button
                onClick={() => setIsOpen(false)}
                style={{
                  background: "rgba(255,255,255,0.2)",
                  border: "none",
                  borderRadius: "50%",
                  width: "28px",
                  height: "28px",
                  color: "white",
                  fontSize: "16px",
                  cursor: "pointer",
                }}
              >
                ✖
              </button>
            </div>

            {/* Messages */}
            <div
              style={{
                flex: 1,
                padding: "12px",
                overflowY: "auto",
                backgroundColor: "#f9fafc",
              }}
            >
              {messages.map((msg, i) => (
                <div
                  key={i}
                  style={{
                    display: "flex",
                    justifyContent:
                      msg.sender === "user" ? "flex-end" : "flex-start",
                    marginBottom: "8px",
                  }}
                >
                  <div
                    style={{
                      padding: "10px 14px",
                      borderRadius: "18px",
                      maxWidth: "70%",
                      fontSize: "14px",
                      lineHeight: "1.4",
                      backgroundColor:
                        msg.sender === "user" ? "#007bff" : "#e5e7eb",
                      color: msg.sender === "user" ? "white" : "black",
                    }}
                  >
                    {msg.text}
                  </div>
                </div>
              ))}

              {/* Show service buttons only if not selected */}
              {!selectedService && (
                <div style={{ display: "flex", gap: "8px", marginTop: "10px" }}>
                  <button
                    onClick={() => handleServiceSelect("Default")}
                    style={{
                      flex: 1,
                      padding: "8px",
                      borderRadius: "12px",
                      border: "1px solid #ccc",
                      cursor: "pointer",
                      background: "#f0f0f0",
                    }}
                  >
                    Default
                  </button>
                  <button
                    onClick={() => handleServiceSelect("ChatGPT")}
                    style={{
                      flex: 1,
                      padding: "8px",
                      borderRadius: "12px",
                      border: "1px solid #ccc",
                      cursor: "pointer",
                      background: "#f0f0f0",
                    }}
                  >
                    ChatGPT
                  </button>
                  <button
                    onClick={() => handleServiceSelect("Perplexity")}
                    style={{
                      flex: 1,
                      padding: "8px",
                      borderRadius: "12px",
                      border: "1px solid #ccc",
                      cursor: "pointer",
                      background: "#f0f0f0",
                    }}
                  >
                    Perplexity
                  </button>
                </div>
              )}

              {/* Loading indicator */}
              {isLoading && (
                <div style={{ display: "flex", justifyContent: "flex-start", marginTop: "8px" }}>
                  <div style={{
                    padding: "10px 14px",
                    borderRadius: "18px",
                    backgroundColor: "#e5e7eb",
                  }}>
                    Typing...
                  </div>
                </div>
              )}
            </div>

            {/* Debug Info - Shows detected URL */}
            {detectedUrl && (
              <div style={{
                padding: "8px",
                backgroundColor: "#fff3cd",
                borderTop: "1px solid #ffc107",
                fontSize: "10px",
                color: "#856404",
                wordBreak: "break-all"
              }}>
                <strong>Detected URL:</strong> {detectedUrl}
              </div>
            )}

            {/* Input */}
            <div
              style={{
                padding: "10px",
                borderTop: "1px solid #eee",
                display: "flex",
                gap: "8px",
              }}
            >
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && handleSend()}
                placeholder="Type a message..."
                style={{
                  flex: 1,
                  padding: "10px",
                  borderRadius: "20px",
                  border: "1px solid #ccc",
                  fontSize: "14px",
                  outline: "none",
                }}
              />
              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={handleSend}
                style={{
                  background: "linear-gradient(135deg, #4e8cff 0%, #007bff 100%)",
                  color: "white",
                  border: "none",
                  borderRadius: "20px",
                  padding: "10px 16px",
                  cursor: "pointer",
                  fontSize: "14px",
                  fontWeight: "bold",
                }}
              >
                ➤
              </motion.button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

export default UiWidget;
